const fs=require("fs"),content=fs.readFileSync("needs_config.js","utf8"),tags=new Set,subContexts=new Set,refinementTags=new Set,nodeLinks=new Set,tagsMatches=content.matchAll(/"tags"\s*:\s*\[([^\]]+)\]/g);for(const o of tagsMatches){o[1].replace(/"/g,"").split(",").map(o=>o.trim()).filter(o=>o).forEach(o=>tags.add(o))}const subContextMatches=content.matchAll(/"sub_context"\s*:\s*"([^"]+)"/g);for(const o of subContextMatches)subContexts.add(o[1]);const filterMatches=content.matchAll(/"profilointi_filter"\s*:\s*\{[^}]*"value"\s*:\s*(?:true|false|"([^"]+)")/g);for(const o of filterMatches)o[1]&&refinementTags.add(o[1]);const nodeLinkMatches=content.matchAll(/"node_link"\s*:\s*"([^"]+)"/g);for(const o of nodeLinkMatches)nodeLinks.add(o[1]);console.log("--- Canonical Tags ---"),console.log(Array.from(tags).sort().join(", ")),console.log("\n--- Canonical SubContexts ---"),console.log(Array.from(subContexts).sort().join(", ")),console.log("\n--- Canonical Refinement Tags ---"),console.log(Array.from(refinementTags).sort().join(", ")),console.log("\n--- Canonical Node Links ---"),console.log(Array.from(nodeLinks).sort().join(", "));